import React from "react"
import Layout from "../../components/Layout"
import Publication from "../../components/Publication"
import { graphql } from "gatsby"
import Pagination from '@material-ui/lab/Pagination';
import useMediaQuery from '@material-ui/core/useMediaQuery';
import { navigate } from "gatsby-plugin-intl"

export default function PageTemplate({ pageContext: { language, collection, series, humanPageNumber, numberOfPages, pathPrefix }, data: { meta, allPub } }) {

	const metadata = meta.siteMetadata.collections.filter(c => c.collection === collection)[0]
	const seriesPlaceholder = meta.siteMetadata.series.filter(s => s.series === series)

	const notsmall = useMediaQuery('(min-width:550px)');

	function MyPagination() {
		if (numberOfPages === 1) return null
		return(
			<Pagination
				count={numberOfPages}
				page={humanPageNumber}
				siblingCount={notsmall ? 2 : 1}
				size={notsmall ? "medium" : "small"}
				onChange={(event, page) => page === 1 ? navigate(pathPrefix) : navigate(`${pathPrefix}/page/${page}`)}
			/>
		)
	}

	return( 
		<Layout
			lang={language}
			metadata={metadata}
			series={series}
			placeholder={(seriesPlaceholder.length > 0 && seriesPlaceholder[0].placeholder) || undefined}
			isList={true}
			// title={series && `${series} Series`}
			// subtitle={series && `PIER ${startCase(collection)}`}
		>
			<div className="bottom-margin-3" style={{display: "flex", justifyContent: "flex-end"}}>
				<MyPagination/>
			</div>
			{
				allPub.nodes.map((node, i) =>
					<Publication data={node} metadata={metadata} key={`publication${i}`} lang={language} />
				)
			}
			<div className="top-margin-3" style={{display: "flex", justifyContent: "flex-end"}}>
				<MyPagination />
			</div>
		</Layout>
	)
}

export const pageQuery = graphql`
	query ($collection: String, $series: String, $skip: Int!, $limit: Int!) {
		meta: site {
			siteMetadata {
				collections {
					collection
					title
					subtitle
					url
					placeholder
				}
				series {
					series
					placeholder
				}
			}
		}
		allPub: allMdx(
			filter: {fields: {collection: {eq: $collection}}, frontmatter: {series: {eq: $series}}},
			sort: {fields: [frontmatter___date, frontmatter___id], order: [DESC, DESC]}
      skip: $skip
      limit: $limit
		) {
			nodes {
        fields {
          collection
					slug
				}
				frontmatter {
					id
					title
					series
					date
					date_end
					location
					authors
          discussants
					cover {
						childImageSharp {
							gatsbyImageData(layout: CONSTRAINED, width: 500)
						}
					}
					gallery {
						childImageSharp {
							gatsbyImageData(layout: CONSTRAINED, width: 500)
						}
					}
					topics
					tags
				}
				authors {
					frontmatter {
						memberid
						title
						exclude
					}
					fields {
						originalPath
						slug
						lang
					}
				}
        discussants {
					frontmatter {
						memberid
						title
						exclude
					}
					fields {
						originalPath
						slug
						lang
					}
				}
			}
		}
	}
`